parameters.jsCode:
var b = $json.body || $json;
var s = b.section;
var reqs = b.requirements;
var spec = b.specData;
var ci = b.contractorInfo;
var prev = b.previousContext || '';
var fb = b.feedback || '';
var pt = b.procurementType || 'неопределен';
var idx = b.sectionIndex;
var total = b.totalSections;
var targetPagesTotal = b.targetPages || 50;
var pages = s.estimated_pages || Math.max(2, Math.round(targetPagesTotal / Math.max(1, total)));
var targetWords = Math.max(60, Math.round(pages * 350));
var maxTokens = Math.min(16000, Math.max(700, Math.round(targetWords * 1.7 + 400)));
var writingRules = b.writingRules || [];
var headingLevel = (s.parentId || s.parentTitle) ? '###' : '##';

var guide = '';
if (s.content_guidance && s.content_guidance.length > 0) {
  guide = '\nУказания от плана:\n';
  for (var g = 0; g < s.content_guidance.length; g++) {
    guide += '- ' + s.content_guidance[g] + '\n';
  }
}
if (s.tables_needed && s.tables_needed.length > 0) {
  guide += '\nТаблици за включване:\n';
  for (var t = 0; t < s.tables_needed.length; t++) {
    var tbl = s.tables_needed[t];
    if (tbl.title) guide += '- ' + tbl.title + (tbl.columns ? ' (' + tbl.columns.join(', ') + ')' : '') + '\n';
  }
}
if (s.spec_data_to_use && s.spec_data_to_use.length > 0) {
  guide += '\nДанни от спецификацията за ползване: ' + s.spec_data_to_use.join(', ') + '\n';
}

var prompt = 'Напиши САМО секция "' + s.id + '. ' + s.title + '" от техническото предложение.\n';
prompt += 'Секция ' + (idx + 1) + ' от ' + total + '. ЦЕЛЕВИ ОБЕМ: ~' + targetWords + ' думи (~' + pages + ' стр.).\n';
prompt += 'ВАЖНО ЗА ОБЕМА: Бъди ИЗЧЕРПАТЕЛЕН по същество, но КОНЦЕНТРИРАН — покрий всичко необходимо в рамките на целевия обем, без разтягане и повторения. По-кратка цел = по-стегнат текст, същата пълнота на покритието.\n\n';
prompt += 'ТИП ПОРЪЧКА: ' + pt + '\n\n';

if (s.requirement_id) {
  var reqArr = reqs.requirements || reqs;
  if (Array.isArray(reqArr)) {
    for (var r = 0; r < reqArr.length; r++) {
      if (reqArr[r].id === s.requirement_id || reqArr[r].id === s.parentId) {
        prompt += 'ИЗИСКВАНЕ НА ВЪЗЛОЖИТЕЛЯ (ДОСЛОВНО):\n' + (reqArr[r].full_text || reqArr[r].title || '') + '\n\n';
        if (reqArr[r].sub_requirements && reqArr[r].sub_requirements.length > 0) {
          prompt += 'ПОД-ИЗИСКВАНИЯ:\n';
          for (var sr = 0; sr < reqArr[r].sub_requirements.length; sr++) {
            prompt += '- ' + reqArr[r].sub_requirements[sr].id + ': ' + reqArr[r].sub_requirements[sr].text + '\n';
          }
          prompt += '\n';
        }
        break;
      }
    }
  }
}

prompt += 'УКАЗАНИЯ ОТ ПЛАНА:\n' + (guide || s.title) + '\n\n';

var filteredSpec = {};
var specKeys = s.spec_data_to_use || [];
if (specKeys.length > 0 && spec) {
  for (var k = 0; k < specKeys.length; k++) {
    var key = specKeys[k];
    if (spec[key] !== undefined) filteredSpec[key] = spec[key];
  }
  if (Object.keys(filteredSpec).length === 0) filteredSpec = spec;
} else {
  filteredSpec = spec;
}
var specJson = JSON.stringify(filteredSpec, null, 2);
if (specJson.length > 15000) specJson = specJson.substring(0, 15000);
prompt += 'ТЕХНИЧЕСКИ ДАННИ ОТ СПЕЦИФИКАЦИЯТА:\n' + specJson + '\n\n';

prompt += 'ИНФОРМАЦИЯ ЗА ИЗПЪЛНИТЕЛЯ:\n' + JSON.stringify(ci, null, 2) + '\n\n';

if (b.documentOutline) {
  prompt += 'ВЕЧЕ НАПИСАНИ СЕКЦИИ (за препратки — НЕ повтаряй съдържанието им):\n' + b.documentOutline + '\n\n';
}
// === Канонични етапи (еднакви за целия документ) ===
var _stages = b.stages || [];
if (_stages.length > 0) {
  prompt += 'КАНОНИЧНИ ЕТАПИ НА ИЗПЪЛНЕНИЕ (ползвай ТОЧНО тези — еднакви за целия документ):\n';
  for (var _si = 0; _si < _stages.length; _si++) {
    prompt += (_si + 1) + '. ' + (_stages[_si].name || '') + (_stages[_si].description ? (' — ' + _stages[_si].description) : '') + '\n';
  }
  prompt += 'Ако тази секция описва етапи, използвай ТОЧНО горните етапи (същите имена и брой). НЕ измисляй други етапи.\n\n';
}
if (prev) {
  prompt += 'ПРЕДИШЕН КОНТЕКСТ (НЕ повтаряй, осигури кохерентност):\n...' + prev.substring(prev.length > 2000 ? prev.length - 2000 : 0) + '\n\n';
}
if (fb) {
  prompt += '⚠️ ОБРАТНА ВРЪЗКА ОТ ВАЛИДАЦИЯ — ЗАДЪЛЖИТЕЛНО ПОПРАВИ:\n' + fb + '\n\n';
}

if (writingRules.length > 0) {
  prompt += '⚠️ ПРАВИЛА ЗА ПИСАНЕ ОТ ДОКУМЕНТАЦИЯТА НА ВЪЗЛОЖИТЕЛЯ:\n';
  for (var wr = 0; wr < writingRules.length; wr++) {
    var rule = writingRules[wr];
    prompt += (wr+1) + '. ' + (rule.rule || '') + '\n';
    if (rule.instruction_for_writer) prompt += '   → ' + rule.instruction_for_writer + '\n';
    if (rule.violation_consequence) prompt += '   ⚠️ При нарушение: ' + rule.violation_consequence + '\n';
  }
  prompt += '\n';
}

prompt += 'ПРАВИЛА ЗА ПИСАНЕ:\n';
prompt += '1. САМО тази секция — започни с ' + headingLevel + ' ' + s.id + '. ' + s.title + '\n';
prompt += '2. За всяка дейност: КАКВО → КАК → С КАКВО → КОЙ → КОНТРОЛ\n';
prompt += '3. Markdown таблици за: оборудване, персонал, графици, контролни планове\n';
prompt += '4. Графици: таблици (Дейност | Последователност | Ресурси | Отговорник) — БЕЗ конкретни срокове, вместо срок пиши \"съгласно Календарния график\"\n';
prompt += '5. БЕЗ плейсхолдери: НЕ използвай маркери от вид [ПОПЪЛНЕТЕ: ...]. Ако конкретни данни липсват, ползвай професионална формулировка по роля/процес\n';
prompt += '6. НЕ измисляй факти, НЕ пиши generic текст приложим за всяка поръчка\n';
prompt += '7. НИКАКВИ конкретни срокове за изпълнение — пиши \"съгласно Календарния график\". НИКАКВИ конкретни гаранционни срокове — пиши \"съгласно гаранционния срок, посочен в техническото предложение\"\n';
prompt += '   ⛔ ИМЕНА: НЕ изписвай лични имена на хора. Споменавай експертите САМО по професионална роля (напр. Електро инженер, Координатор по безопасност) — БЕЗ имена и БЕЗ плейсхолдери\n';
prompt += '7. Текстът ТРЯБВА да отчита спецификата на КОНКРЕТНАТА поръчка — конкретни обекти, артикули, местоположения, количества от спецификацията\n';
prompt += '8. НЕ повтаряй текст от предишните секции — препращай: "Както е описано в т. X.X..."\n';
prompt += '9. НЕ пиши въведение/заключение на ЦЕЛИЯ документ\n';
prompt += '10. ФОРМАТ НА МЕРКИ: Ако секцията изисква мярка, всяка мярка е САМОСТОЯТЕЛНА и включва:\n';
prompt += '   а) Наименование и същност на мярката\n';
prompt += '   б) Конкретни дейности за изпълнение\n';
prompt += '   в) Времеви план за прилагане\n';
prompt += '   г) Конкретен експерт + конкретни задължения\n';
prompt += '   д) Контролни дейности и мониторинг (честота, действия при отклонения, лица за контрол)\n';
prompt += '   е) Очакван и целен ефект от мярката\n';
prompt += '   НЕ обединявай елементи от различни мерки!\n';
prompt += '11. Текстът НЕ ТРЯБВА да е формален — трябва да показва реално разбиране на конкретната поръчка\n';
if (_stages.length > 0) {
  prompt += '12. ЗА ВСЕКИ ЕТАП (ЗАДЪЛЖИТЕЛНО): Ако тази секция изисква нещо ЗА ВСЕКИ ЕТАП (напр. експерти, задължения, ресурси по етапи), направи ОТДЕЛНА подсекция ИЛИ ред в таблица за ВСЕКИ от ' + _stages.length + '-те канонични етапа — нито един етап да не липсва.\n';
}


// === Приоритет 4: правило за СМР срокове (само строителство/смесена) ===
if (pt && (pt.toLowerCase().indexOf('строит') >= 0 || pt.toLowerCase().indexOf('смесен') >= 0)) {
  prompt += '\n⚠️ СРОКОВЕ ЗА СМР ДЕЙНОСТИ:\n';
  prompt += 'За строителни и монтажни дейности (изкопи, насипи, кофраж, армиране, бетониране, зидария, монтаж, полагане на настилки/изолации и подобни СМР) НЕ посочвай конкретни дни, седмици или периоди.\n';
  prompt += 'Вместо това ВИНАГИ пиши: "в срок съгласно одобрения линеен календарен график".\n';
  prompt += 'Пример: НЕ "наливане на бетон — 1 седмица", А "наливане на бетон — в срок съгласно одобрения линеен календарен график".\n';
  prompt += 'ИЗКЛЮЧЕНИЯ (остават с конкретни срокове): гаранционна реакция (напр. отзив до 4 часа), комуникация (напр. отговор до 24 часа), мобилизация, срокове за отстраняване на дефекти.\n';
  prompt += 'Самият линеен календарен график (в посветената му подсекция/таблица) се представя нормално — правилото важи за описанията на СМР дейности в текста.\n';
}

return [{ json: { prompt: prompt, maxTokens: maxTokens, targetWords: targetWords } }];

var raw = ($json.text || $json.response || '').trim();

// Handle error from chainLlm (onError: continueRegularOutput)
if ($json.error || $json.errorMessage || (!raw && $input.first().json.error)) {
  var errMsg = $json.errorMessage || $json.error || 'Unknown AI error';
  if (typeof errMsg === 'object') errMsg = JSON.stringify(errMsg);
  return [{
    json: {
      sectionText: '',
      error: true,
      errorMessage: String(errMsg).substring(0, 500),
      stats: { wordCount: 0, estimatedPages: 0, placeholders: 0, tables: 0 }
    }
  }];
}

// === SAFETY NET (Приоритет 3): премахни ВСЯКАКВИ плейсхолдери ===
var placeholders = (raw.match(/\[[^\]]*ПОПЪЛНЕТЕ:[^\]]*\]/gi) || []).length;
raw = raw.replace(/[ \t]*\[[^\]]*ПОПЪЛНЕТЕ:[^\]]*\]/gi, '');
raw = raw.replace(/[ \t]{2,}/g, ' ');
raw = raw.replace(/[ \t]+([,.;:!?])/g, '$1');
raw = raw.replace(/:\s*—/g, ' —');
raw = raw.replace(/\(\s*\)/g, '');
var wordCount = raw.split(/\s+/).length;
var tableCount = (raw.match(/\|.*\|/g) || []).length;

return [{
  json: {
    sectionText: raw,
    stats: {
      wordCount: wordCount,
      estimatedPages: Math.round(wordCount / 375),
      placeholders: placeholders,
      tables: Math.floor(tableCount / 3)
    }
  }
}];
